1	<script lang="ts">
2		import type { LayoutData } from './$types';
3		import type { Snippet } from 'svelte';
4		import { goto, invalidateAll } from '$app/navigation';
5		import { page } from '$app/stores';
6		import { createClient } from '$lib/gql/client';
7		import { subscribeWorkerProgress } from '$lib/gql/subscriptions';
8		import { gql } from 'graphql-request';
9	
10		let { data, children }: { data: LayoutData; children: Snippet } = $props();
11	
12		const START_WORKER_MUTATION = gql`
13			mutation StartWorker($input: StartWorkerInput!) {
14				startWorker(input: $input) {
15					id
16					state
17					kind
18				}
19			}
20		`;
21	
22		const STOP_WORKER_MUTATION = gql`
23			mutation StopWorker($id: ID!) {
24				stopWorker(id: $id) {
25					id
26					state
27					kind
28				}
29			}
30		`;
31	
32		// + Add worker dispatches a default-spec drain worker (ddx-b6cf025c). The
33		// server honours .ddx/config.yaml workers.default_spec + workers.max_count.
34		const ADD_WORKER_MUTATION = gql`
35			mutation AddDrainWorker($projectId: String!) {
36				workerDispatch(kind: "execute-loop", projectId: $projectId) {
37					id
38					state
39					kind
40				}
41			}
42		`;
43	
44		// Live phase overrides from workerProgress subscription (workerID -> phase)
45		let livePhaseOverrides = $state<Map<string, string>>(new Map());
46		let showStartForm = $state(false);
47		let starting = $state(false);
48		let stoppingId = $state<string | null>(null);
49		let actionError = $state<string | null>(null);
50		let harness = $state('');
51		let profile = $state('smart');
52		let effort = $state('medium');
53		let labelFilter = $state('');
54		let adding = $state(false);
55		let removing = $state(false);
56	
57		// Drain workers: count of running execute-loop workers.
58		const runningDrainCount = $derived(
59			data.workers.edges.filter(
60				(e) => e.node.state === 'running' && e.node.kind === 'execute-loop'
61			).length
62		);
63	
64		// workers.max_count safety rail (ddx-b6cf025c). Null = no cap configured.
65		const maxCount = $derived(data.maxCount);
66		const atMaxCount = $derived(
67			typeof maxCount === 'number' && maxCount >= 0 && runningDrainCount >= maxCount
68		);
69		const addDisabled = $derived(adding || atMaxCount);
70		const addTooltip = $derived(
71			atMaxCount ? 'at workers.max_count limit' : 'Add a general-purpose drain worker'
72		);
73	
74		// Subscribe to progress events for all running workers
75		$effect(() => {
76			const runningIds = data.workers.edges
77				.filter((e) => e.node.state === 'running')
78				.map((e) => e.node.id);
79	
80			livePhaseOverrides = new Map();
81	
82			const disposes = runningIds.map((workerID) =>
83				subscribeWorkerProgress(workerID, (evt) => {
84					const next = new Map(livePhaseOverrides);
85					next.set(evt.workerID, evt.phase);
86					livePhaseOverrides = next;
87				})
88			);
89	
90			return () => disposes.forEach((d) => d());
91		});
92	
93		// The currently open worker (from child route params)
94		let activeWorker = $derived(($page.params as Record<string, string>)['workerId'] ?? null);
95	
96		function openWorker(workerId: string) {
97			const p = $page.params as Record<string, string>;
98			goto(`/nodes/${p['nodeId']}/projects/${p['projectId']}/workers/${workerId}`);
99		}
100	
101		function sessionsHref(): string {
102			const p = $page.params as Record<string, string>;
103			return `/nodes/${p['nodeId']}/projects/${p['projectId']}/sessions`;
104		}
105	
106		function errorText(err: unknown): string {
107			return err instanceof Error ? err.message : 'Worker action failed.';
108		}
109	
110		async function startWorker() {
111			actionError = null;
112			if (!profile.trim() || !effort.trim()) {
113				actionError = 'Profile and effort are required.';
114				return;
115			}
116			starting = true;
117			try {
118				const client = createClient(fetch);
119				await client.request(START_WORKER_MUTATION, {
120					input: {
121						projectId: data.projectId,
122						harness: harness.trim() || null,
123						profile: profile.trim(),
124						effort: effort.trim(),
125						labelFilter: labelFilter.trim() || null
126					}
127				});
128				showStartForm = false;
129				harness = '';
130				labelFilter = '';
131				await invalidateAll();
132			} catch (err) {
133				actionError = errorText(err);
134			} finally {
135				starting = false;
136			}
137		}
138	
139		async function addDrainWorker() {
140			actionError = null;
141			adding = true;
142			try {
143				const client = createClient(fetch);
144				await client.request(ADD_WORKER_MUTATION, { projectId: data.projectId });
145				await invalidateAll();
146			} catch (err) {
147				actionError = errorText(err);
148			} finally {
149				adding = false;
150			}
151		}
152	
153		async function removeDrainWorker() {
154			actionError = null;
155			// Find the oldest running execute-loop worker (AC #4: "stops the oldest-
156			// running drain worker"). data.workers is sorted newest-first, so the
157			// last matching edge is oldest.
158			const runningDrain = data.workers.edges
159				.filter((e) => e.node.state === 'running' && e.node.kind === 'execute-loop')
160				.map((e) => e.node);
161			const target = runningDrain[runningDrain.length - 1];
162			if (!target) return;
163			if (!window.confirm(`Stop worker ${target.id}?`)) return;
164			removing = true;
165			try {
166				const client = createClient(fetch);
167				await client.request(STOP_WORKER_MUTATION, { id: target.id });
168				await invalidateAll();
169			} catch (err) {
170				actionError = errorText(err);
171			} finally {
172				removing = false;
173			}
174		}
175	
176		async function stopWorker(event: MouseEvent, workerId: string) {
177			event.stopPropagation();
178			actionError = null;
179			if (!window.confirm(`Stop worker ${workerId}?`)) return;
180			stoppingId = workerId;
181			try {
182				const client = createClient(fetch);
183				await client.request(STOP_WORKER_MUTATION, { id: workerId });
184				await invalidateAll();
185			} catch (err) {
186				actionError = errorText(err);
187			} finally {
188				stoppingId = null;
189			}
190		}
191	
192		function stateClass(state: string): string {
193			switch (state) {
194				case 'running':
195					return 'text-status-running';
196				case 'idle':
197					return 'text-status-open';
198				case 'stopped':
199					return 'text-fg-muted dark:text-dark-fg-muted';
200				case 'error':
201					return 'text-status-failed';
202				default:
203					return 'text-fg-muted dark:text-dark-fg-muted';
204			}
205		}
206	</script>
207	
208	<div class="space-y-4">
209		<!-- Drain-worker count control (ddx-b6cf025c). Dispatches a default-spec
210		     worker; server enforces workers.default_spec + workers.max_count. -->
211		<div
212			data-testid="drain-count-panel"
213			class="flex flex-col gap-3 border border-border-line bg-bg-surface p-4 text-body-sm dark:border-dark-border-line dark:bg-dark-bg-surface sm:flex-row sm:items-center sm:justify-between"
214		>
215			<div>
216				<div class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">
217					Drain workers
218				</div>
219				<div
220					data-testid="drain-worker-count"
221					class="mt-1 text-headline-lg font-headline-lg text-fg-ink dark:text-dark-fg-ink"
222				>
223					{runningDrainCount}
224				</div>
225				<p class="mt-1 text-body-sm text-fg-muted dark:text-dark-fg-muted">
226					Adds a general-purpose drain worker. Use the per-harness picker below for custom specs.
227				</p>
228			</div>
229			<div class="flex items-center gap-2">
230				<button
231					type="button"
232					data-testid="add-drain-worker"
233					onclick={() => void addDrainWorker()}
234					disabled={addDisabled}
235					title={addTooltip}
236					class="border border-accent-lever bg-accent-lever px-3 py-1.5 text-body-sm font-medium text-white hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-accent-lever dark:bg-dark-accent-lever"
237					aria-label="Add worker"
238				>
239					{adding ? '…' : '+ Add worker'}
240				</button>
241				<button
242					type="button"
243					data-testid="remove-drain-worker"
244					onclick={() => void removeDrainWorker()}
245					disabled={removing || runningDrainCount === 0}
246					class="border border-border-line px-3 py-1.5 text-body-sm font-medium text-error hover:bg-bg-canvas disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-border-line dark:text-dark-error dark:hover:bg-dark-bg-surface"
247					aria-label="Remove worker"
248				>
249					{removing ? '…' : '− Remove worker'}
250				</button>
251			</div>
252		</div>
253	
254		<div class="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
255			<div>
256				<h1 class="text-headline-lg font-headline-lg text-fg-ink dark:text-dark-fg-ink">Workers</h1>
257				<p class="mt-1 max-w-2xl text-body-sm text-fg-muted dark:text-dark-fg-muted">
258					Workers drain the bead queue as long-lived processes; Sessions are the history of
259					what they ran.
260				</p>
261				<a class="mt-2 inline-flex text-body-sm text-accent-lever hover:underline dark:text-dark-accent-lever" href={sessionsHref()}>
262					Recent sessions →
263				</a>
264			</div>
265			<div class="flex items-center gap-3">
266				<span class="text-body-sm text-fg-muted dark:text-dark-fg-muted">
267					{data.workers.totalCount} total
268				</span>
269				<button
270					type="button"
271					onclick={() => {
272						actionError = null;
273						showStartForm = !showStartForm;
274					}}
275					class="border border-accent-lever bg-accent-lever px-3 py-1.5 text-body-sm font-medium text-white hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-accent-lever dark:bg-dark-accent-lever"
276				>
277					Start worker
278				</button>
279			</div>
280		</div>
281	
282		{#if showStartForm}
283			<form
284				class="grid gap-3 border border-border-line bg-bg-surface p-4 text-body-sm dark:border-dark-border-line dark:bg-dark-bg-surface sm:grid-cols-4"
285				onsubmit={(event) => {
286					event.preventDefault();
287					void startWorker();
288				}}
289			>
290				<label class="space-y-1">
291					<span class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Harness</span>
292					<input
293						bind:value={harness}
294						placeholder="auto"
295						class="w-full border border-border-line bg-bg-elevated px-2 py-1.5 text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
296					/>
297				</label>
298				<label class="space-y-1">
299					<span class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Profile</span>
300					<select
301						bind:value={profile}
302						required
303						class="w-full border border-border-line bg-bg-elevated px-2 py-1.5 text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
304					>
305						<option value="cheap">cheap</option>
306						<option value="fast">fast</option>
307						<option value="smart">smart</option>
308					</select>
309				</label>
310				<label class="space-y-1">
311					<span class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Effort</span>
312					<select
313						bind:value={effort}
314						required
315						class="w-full border border-border-line bg-bg-elevated px-2 py-1.5 text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
316					>
317						<option value="low">low</option>
318						<option value="medium">medium</option>
319						<option value="high">high</option>
320					</select>
321				</label>
322				<label class="space-y-1">
323					<span class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Label filter</span>
324					<input
325						bind:value={labelFilter}
326						placeholder="optional"
327						class="w-full border border-border-line bg-bg-elevated px-2 py-1.5 text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
328					/>
329				</label>
330				<div class="flex items-end gap-2 sm:col-span-4">
331					<button
332						type="submit"
333						disabled={starting || !profile.trim() || !effort.trim()}
334						class="border border-fg-ink bg-fg-ink px-3 py-1.5 text-body-sm font-medium text-bg-canvas hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-fg-ink dark:bg-dark-fg-ink dark:text-dark-bg-canvas"
335					>
336						{starting ? 'Starting…' : 'Start'}
337					</button>
338					<button
339						type="button"
340						onclick={() => (showStartForm = false)}
341						class="px-3 py-1.5 text-body-sm text-fg-muted hover:bg-bg-canvas dark:text-dark-fg-muted dark:hover:bg-dark-bg-surface"
342					>
343						Cancel
344					</button>
345				</div>
346			</form>
347		{/if}
348	
349		{#if actionError}
350			<div class="border border-border-line bg-bg-surface px-3 py-2 text-body-sm text-status-failed dark:border-dark-border-line dark:bg-dark-bg-surface">
351				{actionError}
352			</div>
353		{/if}
354	
355		<div class="overflow-hidden border border-border-line dark:border-dark-border-line">
356			<table class="w-full text-body-sm">
357				<thead>
358					<tr class="border-b border-border-line bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-surface">
359						<th class="px-4 py-3 text-left text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">ID</th>
360						<th class="px-4 py-3 text-left text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Kind</th>
361						<th class="px-4 py-3 text-left text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted"
362							>State / Phase</th
363						>
364						<th class="px-4 py-3 text-left text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted"
365							>Current Bead</th
366						>
367						<th class="px-4 py-3 text-right text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted"
368							>Attempts</th
369						>
370						<th class="px-4 py-3 text-right text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Actions</th>
371					</tr>
372				</thead>
373				<tbody>
374					{#each data.workers.edges as edge (edge.cursor)}
375						<tr
376							onclick={() => openWorker(edge.node.id)}
377							class="cursor-pointer border-b border-border-line last:border-0 hover:bg-bg-surface dark:border-dark-border-line dark:hover:bg-dark-bg-surface {activeWorker ===
378							edge.node.id
379								? 'bg-accent-lever/10 dark:bg-dark-accent-lever/10'
380								: ''}"
381						>
382							<td class="px-4 py-3 font-mono-code text-mono-code text-accent-lever dark:text-dark-accent-lever">
383								{edge.node.id.slice(0, 8)}
384							</td>
385							<td class="px-4 py-3 text-fg-ink dark:text-dark-fg-ink">
386								{edge.node.kind}
387							</td>
388							<td class="px-4 py-3">
389								<span
390									class="font-medium {stateClass(
391										livePhaseOverrides.get(edge.node.id) ?? edge.node.state
392									)}"
393								>
394									{livePhaseOverrides.get(edge.node.id) ?? edge.node.state}
395								</span>
396							</td>
397							<td class="px-4 py-3 font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted">
398								{edge.node.currentBead ?? '—'}
399							</td>
400							<td class="px-4 py-3 text-right text-fg-muted dark:text-dark-fg-muted">
401								{#if edge.node.attempts != null}
402									<span title="{edge.node.successes ?? 0}✓ / {edge.node.failures ?? 0}✗">
403										{edge.node.attempts}
404									</span>
405								{:else}
406									—
407								{/if}
408							</td>
409							<td class="px-4 py-3 text-right">
410								{#if edge.node.state === 'running'}
411									<button
412										type="button"
413										onclick={(event) => stopWorker(event, edge.node.id)}
414										disabled={stoppingId === edge.node.id}
415										class="border border-border-line px-2 py-1 text-xs font-medium text-status-failed hover:bg-bg-canvas disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-border-line dark:hover:bg-dark-bg-surface"
416									>
417										{stoppingId === edge.node.id ? 'Stopping…' : 'Stop'}
418									</button>
419								{:else}
420									<span class="text-mono-code text-fg-muted dark:text-dark-fg-muted">—</span>
421								{/if}
422							</td>
423						</tr>
424					{/each}
425					{#if data.workers.edges.length === 0}
426						<tr>
427							<td colspan="6" class="px-4 py-8 text-center text-body-sm text-fg-muted dark:text-dark-fg-muted">
428								No workers found. Nothing is draining this queue right now; start a worker here
429								or run ddx work from a terminal.
430							</td>
431						</tr>
432					{/if}
433				</tbody>
434			</table>
435		</div>
436	</div>
437	
438	{@render children()}
439
